import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.Wufm-cgV.js";const g=JSON.parse('{"title":"Alerting","description":"Configuring alert rules and notification channels","frontmatter":{"title":"Alerting","description":"Configuring alert rules and notification channels"},"headers":[],"relativePath":"guide/alerting.md","filePath":"guide/alerting.md"}'),o={name:"guide/alerting.md"};function n(l,e,d,s,h,c){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="alerting" tabindex="-1">Alerting <a class="header-anchor" href="#alerting" aria-label="Permalink to &quot;Alerting&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>WebRouter&#39;s alert engine evaluates rules every minute and sends notifications when conditions are met.</p><h2 id="alert-rules" tabindex="-1">Alert Rules <a class="header-anchor" href="#alert-rules" aria-label="Permalink to &quot;Alert Rules&quot;">​</a></h2><h3 id="error-rate-alert" tabindex="-1">Error Rate Alert <a class="header-anchor" href="#error-rate-alert" aria-label="Permalink to &quot;Error Rate Alert&quot;">​</a></h3><p>Triggered when a provider&#39;s error rate exceeds a threshold in a time window:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Threshold</td><td>Error rate (e.g., 0.1 = 10%)</td></tr><tr><td>Window</td><td>Evaluation period in minutes</td></tr></tbody></table><h3 id="quota-remaining-alert" tabindex="-1">Quota Remaining Alert <a class="header-anchor" href="#quota-remaining-alert" aria-label="Permalink to &quot;Quota Remaining Alert&quot;">​</a></h3><p>Triggered when a token&#39;s remaining quota drops below a percentage:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Threshold</td><td>Remaining percentage (e.g., 0.2 = 20%)</td></tr><tr><td>Scope</td><td><code>token</code> or <code>organization</code></td></tr></tbody></table><h3 id="provider-down-alert" tabindex="-1">Provider Down Alert <a class="header-anchor" href="#provider-down-alert" aria-label="Permalink to &quot;Provider Down Alert&quot;">​</a></h3><p>Triggered when a provider is consistently failing:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Max Retries</td><td>Consecutive failures before alert</td></tr><tr><td>Window</td><td>Evaluation period in minutes</td></tr></tbody></table><h2 id="alert-levels" tabindex="-1">Alert Levels <a class="header-anchor" href="#alert-levels" aria-label="Permalink to &quot;Alert Levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Color</th><th>Behavior</th></tr></thead><tbody><tr><td><code>critical</code></td><td>Red</td><td>All configured channels</td></tr><tr><td><code>warning</code></td><td>Yellow</td><td>Notify but no escalation</td></tr><tr><td><code>info</code></td><td>Blue</td><td>Informational only</td></tr></tbody></table><h2 id="notification-channels" tabindex="-1">Notification Channels <a class="header-anchor" href="#notification-channels" aria-label="Permalink to &quot;Notification Channels&quot;">​</a></h2><h3 id="email" tabindex="-1">Email <a class="header-anchor" href="#email" aria-label="Permalink to &quot;Email&quot;">​</a></h3><p>Configure SMTP settings in <strong>Settings</strong> → <strong>Alert Settings</strong>:</p><ul><li>SMTP host, port, user, password</li><li>From address and recipient list</li><li>TLS support</li></ul><h3 id="wechat" tabindex="-1">WeChat <a class="header-anchor" href="#wechat" aria-label="Permalink to &quot;WeChat&quot;">​</a></h3><p>Use ServerChan (PushBear) for WeChat notifications:</p><ul><li>Get a SendKey from <a href="https://sct.ftqq.com" target="_blank" rel="noreferrer">sct.ftqq.com</a></li><li>Enter it in <strong>Settings</strong> → <strong>Alert Settings</strong></li></ul><h2 id="cooldown" tabindex="-1">Cooldown <a class="header-anchor" href="#cooldown" aria-label="Permalink to &quot;Cooldown&quot;">​</a></h2><p>To prevent alert fatigue, alerts have a cooldown period (default: 5 minutes). The same alert will not fire again until the cooldown expires.</p>',24)])])}const p=t(o,[["render",n]]);export{g as __pageData,p as default};
